**Step 2: Implement Handler Function**
```cpp
static common_chat_params common_chat_params_init_your_template(
    const common_chat_template &    tmpl,
    const autoparser::generation_params & inputs) {

    common_chat_params data;

    // Option A: Just apply template directly
    data.prompt = common_chat_template_direct_apply_impl(tmpl, inputs);
    data.format = COMMON_CHAT_FORMAT_PEG_NATIVE;

    // Option B: Transform messages before rendering
    auto adjusted_messages = json::array();
    // ... transform logic like Ministral does ...
    data.prompt = common_chat_template_direct_apply_impl(
        tmpl, inputs, adjusted_messages);

    // Option C: Define custom PEG parser for output parsing
    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
        // Define parsing grammar for model output
        // See Ministral/Functionary for examples
        return p.prefix(inputs.generation_prompt) << p.content(p.rest());
    });
    data.parser = parser.save();

    // Define preserved tokens that must not be tokenized
    data.preserved_tokens = { "[SPECIAL_TOKEN]" };

    // Optionally define grammar for constrained generation
    if (has_tools) {
        data.grammar = build_grammar([&](const common_grammar_builder & builder) {
            // ... build grammar for tool calls ...
        });
        data.grammar_lazy = true;  // Only apply after certain tokens
        data.grammar_triggers = {
            { COMMON_GRAMMAR_TRIGGER_TYPE_WORD, "[TRIGGER_TOKEN]" }
        };
    }

    return data;
}
```

**Step 3: Register Handler**
Add call to your handler in `common_chat_try_specialized_template()` before the `return std::nullopt;`

